def _evaluate_sequences(instance, sequences):
    machines, durations = _instance_arrays(instance)
    n_jobs = len(machines)
    n_machines = int(instance.num_machines)
    offsets = []
    node_to_op = []
    idx = 0
    for j in range(n_jobs):
        offsets.append(idx)
