            a = offsets[j] + k
            b = offsets[j] + k + 1
            succ[a].append(b)
            indeg[b] += 1

    machine_node_seq = [[] for _ in range(n_machines)]
    for m in range(n_machines):
        counts = {}
        for j in sequences[m]:
