        ends[(j, k)] = en
        if en > makespan:
            makespan = en
            last_node = u

    return makespan, starts, ends, pred, node_to_op, machine_node_seq, last_node


def _critical_swap_candidates(ev):
    cur_ms, cur_starts, cur_ends, pred, node_to_op, machine_node_seq, last_node = ev
    critical = set()
    u = last_node
