    head = 0
    starts_arr = [0] * n_nodes
    pred = [-1] * n_nodes
    order_count = 0
    while head < len(queue):
        u = queue[head]
        head += 1
        order_count += 1
        j, k = node_to_op[u]
        finish = starts_arr[u] + durations[j][k]
        for v in succ[u]:
            if finish > starts_arr[v]:
                starts_arr[v] = finish
