    order_count = 0
    while head < len(queue):
        u = queue[head]
        head += 1
        order_count += 1
        j, k = node_to_op[u]
        finish = starts_arr[u] + durations[j][k]
        for v in succ[u]:
            if finish > starts_arr[v]:
                starts_arr[v] = finish
                pred[v] = u
            indeg[v] -= 1
            if indeg[v] == 0:
                queue.append(v)

    if order_count != n_nodes:
        return None

    starts = {}
    ends = {}
    makespan = 0
    last_node = -1
    for u, (j, k) in enumerate(node_to_op):
        st = starts_arr[u]
        en = st + durations[j][k]
        starts[(j, k)] = st
        ends[(j, k)] = en
        if en > makespan:
            makespan = en
            last_node = u

    return makespan, starts, ends, pred, node_to_op, machine_node_seq, last_node


def _critical_swap_candidates(ev):
    cur_ms, cur_starts, cur_ends, pred, node_to_op, machine_node_seq, last_node = ev
    critical = set()
    u = last_node
    while u >= 0:
        critical.add(u)
        u = pred[u]

    candidates = []
    for m, nodes in enumerate(machine_node_seq):
        block = []
        for p in range(len(nodes) - 1):
            a = nodes[p]
            b = nodes[p + 1]
            if a in critical and b in critical:
                ja, ka = node_to_op[a]
                jb, kb = node_to_op[b]
                if cur_ends.get((ja, ka), -1) == cur_starts.get((jb, kb), -2):
                    block.append((m, p))
            else:
                if len(block) >= 1:
                    candidates.extend(block)
                block = []
        if len(block) >= 1:
            candidates.extend(block)
    return candidates


def _critical_block_descent(instance, initial, max_seconds=4.0):
    deadline = time.time() + max_seconds
    best_ms, best_seq, best_starts, best_ends = initial
    best_seq = [list(x) for x in best_seq]

    ev = _evaluate_sequences(instance, best_seq)
    if ev is not None and ev[0] <= best_ms:
        best_ms, best_starts, best_ends = ev[0], ev[1], ev[2]

    no_improve_rounds = 0
    while time.time() < deadline and no_improve_rounds < 3:
        ev = _evaluate_sequences(instance, best_seq)
        if ev is None:
            break
        cur_ms = ev[0]
        candidates = _critical_swap_candidates(ev)
        if not candidates:
            break

        best_neighbor = None
        best_neighbor_ms = cur_ms
        best_neighbor_data = None

        for m, p in candidates:
            if time.time() >= deadline:
                break
            trial = [list(x) for x in best_seq]
            trial[m][p], trial[m][p + 1] = trial[m][p + 1], trial[m][p]
            tev = _evaluate_sequences(instance, trial)
            if tev is not None and tev[0] < best_neighbor_ms:
                best_neighbor_ms = tev[0]
                best_neighbor = trial
                best_neighbor_data = tev

        if best_neighbor is not None:
            best_seq = best_neighbor
            best_ms = best_neighbor_ms
            best_starts = best_neighbor_data[1]
            best_ends = best_neighbor_data[2]
            no_improve_rounds = 0
        else:
            no_improve_rounds += 1
            break

    return best_ms, best_seq, best_starts, best_ends


def _critical_block_ils(instance, initial, max_seconds=8.0, seed=9173):
    deadline = time.time() + max_seconds
    rng = random.Random(seed)

    ev0 = _evaluate_sequences(instance, initial[1])
    if ev0 is None:
        return initial

    best_ms = ev0[0]
    best_seq = [list(x) for x in initial[1]]
    best_starts = ev0[1]
    best_ends = ev0[2]

    current_seq = [list(x) for x in best_seq]
    current_ms = best_ms
    current_data = ev0
    stale = 0

    while time.time() < deadline:
        improved = False
        ev = current_data if current_data is not None else _evaluate_sequences(instance, current_seq)
        if ev is None:
            current_seq = [list(x) for x in best_seq]
            current_ms = best_ms
            current_data = _evaluate_sequences(instance, current_seq)
            continue

        candidates = _critical_swap_candidates(ev)
        rng.shuffle(candidates)

        best_local_seq = None
        best_local_data = None
        best_local_ms = current_ms

        for m, p in candidates:
            if time.time() >= deadline:
                break
            trial = [list(x) for x in current_seq]
            trial[m][p], trial[m][p + 1] = trial[m][p + 1], trial[m][p]
            tev = _evaluate_sequences(instance, trial)
