                best_local_ms = tev[0]
                best_local_seq = trial
                best_local_data = tev
                if best_local_ms < best_ms:
                    break

        if best_local_seq is not None:
            current_seq = best_local_seq
            current_ms = best_local_ms
            current_data = best_local_data
            improved = True
            stale = 0
            if current_ms < best_ms:
                best_ms = current_ms
                best_seq = [list(x) for x in current_seq]
                best_starts = current_data[1]
                best_ends = current_data[2]

