    machine_loads = [0] * n_machines
    for j in range(n_jobs):
        for k, m in enumerate(machines[j]):
            machine_loads[m] += durations[j][k]
    lower_bound = max(job_load_lb, max(machine_loads) if machine_loads else 0)
