        def key_fn(x):
            j, k, m, d, est, ect = x
            rem = suffix[j][k]
            rem_after = suffix[j][k + 1]
            if rule == "spt":
                return (d, est, -rem, random_tie[j], j)
            if rule == "lpt":
                return (-d, est, -rem, random_tie[j], j)
            if rule == "mwkr":
                return (-rem, est, d, random_tie[j], j)
            if rule == "mor":
