    if sum(len(x) for x in machine_orders) != n_ops:
        return None

    succ = [[] for _ in range(n_ops)]
    indeg = [0] * n_ops

    def add_arc(a, b):
        ia = op_id[a]
        ib = op_id[b]
        succ[ia].append(ib)
        indeg[ib] += 1

    for j in range(n_jobs):
        for k in range(len(machines[j]) - 1):
            add_arc((j, k), (j, k + 1))

    for m in range(n_machines):
        order = machine_orders[m]
        for p in range(len(order) - 1):
            add_arc(order[p], order[p + 1])

    ready = [i for i in range(n_ops) if indeg[i] == 0]
    head = 0
    starts = [0] * n_ops
    topo_count = 0
    while head < len(ready):
        u = ready[head]
        head += 1
        topo_count += 1
        end_u = starts[u] + dur[u]
        for v in succ[u]:
            if starts[v] < end_u:
                starts[v] = end_u
            indeg[v] -= 1
            if indeg[v] == 0:
                ready.append(v)

    if topo_count != n_ops:
        return None

