    return max(job_ready) if job_ready else 0, seq, starts, ends


def _best_greedy_schedule(instance, time_limit=8.0):
    start_time = time.time()
    rules = ["mwkr", "ect", "spt", "lpt", "mor", "lookahead", "critical", "dense", "tail"]
    gt_rules = ["mwkr", "ect", "spt", "lpt", "mor", "lookahead", "critical", "tail"]
